/*
================================================================================
Seed Data: Productos de Alta Rotación (México 2025)
Objetivo: Poblar catálogo inicial con 250 productos reales.
================================================================================
*/

USE [dcmo_utm_dacb];
GO

SET NOCOUNT ON;
SET XACT_ABORT ON;

BEGIN TRY
    BEGIN TRANSACTION;

    -- Limpieza de datos previa (DELETE por existir Foreign Keys)
    DELETE FROM [dbo].[DetalleVenta];
    DELETE FROM [dbo].[Producto];
    
    -- Reinicio de Identidad
    DBCC CHECKIDENT ('[dbo].[Producto]', RESEED, 0);

    PRINT 'Iniciando carga de 250 productos...';

    SET IDENTITY_INSERT [dbo].[Producto] ON;


    SET IDENTITY_INSERT [dbo].[Producto] OFF;

    -- Sincronización del contador de identidad después de la carga manual
    DBCC CHECKIDENT ('[dbo].[Producto]', RESEED, 250);

    COMMIT TRANSACTION;
    PRINT 'Carga de 250 productos completada con éxito.';
END TRY
BEGIN CATCH
    IF @@TRANCOUNT > 0 ROLLBACK TRANSACTION;
    PRINT 'Error detectado en la carga de datos.';
    THROW;
END CATCH;
GO
